def merge_intervals(input):
    if not input or len(input) <= 1:
        return input

    sorted_list = sorted(input, key=lambda x:x[0])
    result = [sorted_list[0]]

    for current in sorted_list[1:]:
        previous = result[-1]
        if current[0] <= previous[1]:
            new_end = max([current[1], previous[1]])
            # we want to take a merge here, so remove current and add the [start, end] with updated value for end of the range
            result.pop()
            result.append((previous[0],new_end))
        else:
            result.append(current)        
    return result if len(result)==1 or input!= sorted(input, key=lambda x:x[0]) else merge_intervals(sorted(sorted_list, key=lambda x:x[0]))
